// Critical caregiver alert delivery (Resend).
// A "critical" alert is a child-safety notification (e.g. an unverified pickup,
// a missed medication window). These MUST reach the caregiver. A per-recipient
// daily quota exists to stop a runaway loop from spamming a caregiver — but the
// quota must never silently drop a genuine critical alert.

import { Resend } from "resend";
import { getDailyCount, incrementDailyCount } from "./quota";

const resend = new Resend(process.env.RESEND_API_KEY);
const DAILY_LIMIT = 50;

export async function sendCriticalAlertEmail(
  caregiverEmail: string,
  subject: string,
  body: string,
): Promise<{ delivered: boolean }> {
  // Enforce the per-caregiver daily quota so a bug can't spam them.
  const sentToday = await getDailyCount(caregiverEmail);
  const overQuota = sentToday >= DAILY_LIMIT;
  if (overQuota) {
    console.warn(
      `[criticalEmail] ${caregiverEmail} over daily quota (${sentToday}/${DAILY_LIMIT})`,
    );
  }

  try {
    await resend.emails.send({
      from: "alerts@example.com",
      to: caregiverEmail,
      subject,
      html: body,
    });
    await incrementDailyCount(caregiverEmail);
    return { delivered: true };
  } catch (err) {
    console.error("[criticalEmail] send failed", err);
    return { delivered: false };
  }
}
